def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    best_node = None
    min_time = np.inf

    for i, customer in enumerate(unvisited_customers):
        for j, truck_pos in enumerate(all_truck_pos):
            time_to_customer = np.linalg.norm(customer - truck_pos) / truck_speed
            time_to_depot = np.linalg.norm(customer - depot_pos) / truck_speed
            total_time = max(current_time + time_to_customer, time_windows[i][0]) + time_windows[i][1] + time_to_depot

            if total_time < min_time:
                min_time = total_time
                best_node = i

    return best_node
